'use strict';

const { allTickets, saveTickets } = require('../core/tickets.js');
const { allComments, saveComments } = require('../core/comments.js');
const { daysBetween } = require('../lib/dates.js');
const config = require('../config.js');
const { AppError } = require('../lib/errors.js');

function purgeStale(args) {
  const apply = args.includes('--apply');

  const tickets = allTickets();
  const comments = allComments();

  // Identify stale tickets: closed AND older than retention window
  const staleTicketIds = new Set();
  for (const ticket of tickets) {
    if (ticket.status === 'closed') {
      const days = daysBetween(ticket.updatedAt, config.referenceDate);
      if (days > config.retentionDays) {
        staleTicketIds.add(ticket.id);
      }
    }
  }

  // Identify comments to cascade-remove
  const staleCommentIds = new Set();
  for (const comment of comments) {
    if (staleTicketIds.has(comment.ticketId)) {
      staleCommentIds.add(comment.id);
    }
  }

  // Empty plan case
  if (staleTicketIds.size === 0) {
    return { lines: ['total: 0'], exitCode: 3 };
  }

  const lines = [];

  // Print plan: tickets first
  for (const ticket of tickets) {
    if (staleTicketIds.has(ticket.id)) {
      lines.push(`plan: purge ticket ${ticket.id}`);
    }
  }

  // Print plan: comments
  for (const comment of comments) {
    if (staleCommentIds.has(comment.id)) {
      lines.push(`plan: purge comment ${comment.id}`);
    }
  }

  const totalCount = staleTicketIds.size + staleCommentIds.size;

  if (apply) {
    // Apply the removal
    const newTickets = tickets.filter(t => !staleTicketIds.has(t.id));
    const newComments = comments.filter(c => !staleCommentIds.has(c.id));

    saveTickets(newTickets);
    saveComments(newComments);

    lines.push(`applied: ${totalCount}`);
  } else {
    lines.push(`total: ${totalCount}`);
  }

  return lines;
}

module.exports = { purgeStale };

